30	export class OpenAIImageModel implements ImageModelV3 {
31	  readonly specificationVersion = 'v3';
32	
33	  get maxImagesPerCall(): number {
34	    return modelMaxImagesPerCall[this.modelId] ?? 1;
35	  }
36	
37	  get provider(): string {
38	    return this.config.provider;
39	  }
40	
41	  constructor(
42	    readonly modelId: OpenAIImageModelId,
43	    private readonly config: OpenAIImageModelConfig,
44	  ) {}
45	
46	  async doGenerate({
47	    prompt,
48	    files,
49	    mask,
50	    n,
51	    size,
52	    aspectRatio,
53	    seed,
54	    providerOptions,
55	    headers,
56	    abortSignal,
57	  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
58	    Awaited<ReturnType<ImageModelV3['doGenerate']>>
59	  > {
60	    const warnings: Array<SharedV3Warning> = [];
61	
62	    if (aspectRatio != null) {
63	      warnings.push({
64	        type: 'unsupported',
65	        feature: 'aspectRatio',
66	        details:
67	          'This model does not support aspect ratio. Use `size` instead.',
68	      });
69	    }
70	
71	    if (seed != null) {
72	      warnings.push({ type: 'unsupported', feature: 'seed' });
73	    }
74	
75	    const currentDate = this.config._internal?.currentDate?.() ?? new Date();
76	
77	    if (files != null) {
78	      const { value: response, responseHeaders } = await postFormDataToApi({
79	        url: this.config.url({
80	          path: '/images/edits',
81	          modelId: this.modelId,
82	        }),
83	        headers: combineHeaders(this.config.headers(), headers),
84	        formData: convertToFormData<OpenAIImageEditInput>({
85	          model: this.modelId,
86	          prompt,
87	          image: await Promise.all(
88	            files.map(file =>
89	              file.type === 'file'
90	                ? new Blob(
91	                    [
92	                      file.data instanceof Uint8Array
93	                        ? new Blob([file.data as BlobPart], {
94	                            type: file.mediaType,
95	                          })
96	                        : new Blob([convertBase64ToUint8Array(file.data)], {
97	                            type: file.mediaType,
98	                          }),
99	                    ],
100	                    { type: file.mediaType },
101	                  )
102	                : downloadBlob(file.url),
103	            ),
104	          ),
105	          mask: mask != null ? await fileToBlob(mask) : undefined,
106	          n,
107	          size,
108	          ...(providerOptions.openai ?? {}),
109	        }),
110	        failedResponseHandler: openaiFailedResponseHandler,
111	        successfulResponseHandler: createJsonResponseHandler(
112	          openaiImageResponseSchema,
113	        ),
114	        abortSignal,
115	        fetch: this.config.fetch,
116	      });
117	
118	      return {
119	        images: response.data.map(item => item.b64_json),
120	        warnings,
121	        usage:
122	          response.usage != null
123	            ? {
124	                inputTokens: response.usage.input_tokens ?? undefined,
125	                outputTokens: response.usage.output_tokens ?? undefined,
126	                totalTokens: response.usage.total_tokens ?? undefined,
127	              }
128	            : undefined,
129	        response: {
130	          timestamp: currentDate,
131	          modelId: this.modelId,
132	          headers: responseHeaders,
133	        },
134	        providerMetadata: {
135	          openai: {
136	            images: response.data.map((item, index) => ({
137	              ...(item.revised_prompt
138	                ? { revisedPrompt: item.revised_prompt }
139	                : {}),
140	              created: response.created ?? undefined,
141	              size: response.size ?? undefined,
142	              quality: response.quality ?? undefined,
143	              background: response.background ?? undefined,
144	              outputFormat: response.output_format ?? undefined,
145	              ...distributeTokenDetails(
146	                response.usage?.input_tokens_details,
147	                index,
148	                response.data.length,
149	              ),
150	            })),
151	          },
152	        },
153	      };
154	    }
155	
156	    const { value: response, responseHeaders } = await postJsonToApi({
157	      url: this.config.url({
158	        path: '/images/generations',
159	        modelId: this.modelId,
160	      }),
161	      headers: combineHeaders(this.config.headers(), headers),
162	      body: {
163	        model: this.modelId,
164	        prompt,
165	        n,
166	        size,
167	        ...(providerOptions.openai ?? {}),
168	        ...(!hasDefaultResponseFormat(this.modelId)
169	          ? { response_format: 'b64_json' }
170	          : {}),
171	      },
172	      failedResponseHandler: openaiFailedResponseHandler,
173	      successfulResponseHandler: createJsonResponseHandler(
174	        openaiImageResponseSchema,
175	      ),
176	      abortSignal,
177	      fetch: this.config.fetch,
178	    });
179	
180	    return {
181	      images: response.data.map(item => item.b64_json),
182	      warnings,
183	      usage:
184	        response.usage != null
185	          ? {
186	              inputTokens: response.usage.input_tokens ?? undefined,
187	              outputTokens: response.usage.output_tokens ?? undefined,
188	              totalTokens: response.usage.total_tokens ?? undefined,
189	            }
190	          : undefined,
191	      response: {
192	        timestamp: currentDate,
193	        modelId: this.modelId,
194	        headers: responseHeaders,
195	      },
196	      providerMetadata: {
197	        openai: {
198	          images: response.data.map((item, index) => ({
199	            ...(item.revised_prompt
200	              ? { revisedPrompt: item.revised_prompt }
201	              : {}),
202	            created: response.created ?? undefined,
203	            size: response.size ?? undefined,
204	            quality: response.quality ?? undefined,
205	            background: response.background ?? undefined,
206	            outputFormat: response.output_format ?? undefined,
207	            ...distributeTokenDetails(
208	              response.usage?.input_tokens_details,
209	              index,
210	              response.data.length,
211	            ),
212	          })),
213	        },
214	      },
215	    };
216	  }
217	}
