export class BlackForestLabsImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 1;  // Single image per call

  async doGenerate({...}): Promise<...> {
    // Step 1: Submit request
    const submit = await postJsonToApi({
      url: `${this.config.baseURL}/${this.modelId}`,
      body: { prompt, ... },
    });

    const pollUrl = submit.value.polling_url;
    const requestId = submit.value.id;

    // Step 2: Poll for result
    const { imageUrl, seed, ... } = await this.pollForImageUrl({
      pollUrl,
      requestId,
      headers,
      pollOverrides: { ... },
    });

    // Step 3: Download final image
    const { value: imageBytes, responseHeaders } = await getFromApi({
      url: imageUrl,
      headers,
      successfulResponseHandler: createBinaryResponseHandler(),
    });

    return {
      images: [imageBytes],  // Binary format
      warnings,
      providerMetadata: {
        blackForestLabs: {
          images: [{ seed, start_time, end_time, duration, cost, ... }]
        }
      },
      response: { modelId, timestamp, headers },
    };
  }

  private async pollForImageUrl({ ... }): Promise<{ imageUrl: string; ... }> {
    // Polling loop with configurable interval and timeout
    for (let i = 0; i < maxPollAttempts; i++) {
      const { value } = await getFromApi({
        url: url.toString(),
        successfulResponseHandler: createJsonResponseHandler(bflPollSchema),
      });

      const status = value.status;
      if (status === 'Ready') {
        return { imageUrl: value.result.sample, ... };
      }
      if (status === 'Error' || status === 'Failed') {
        throw new Error('Black Forest Labs generation failed.');
