          prompt,
          image: await Promise.all(
            files.map(file => /* convert to Blob */)
          ),
          mask: mask != null ? await fileToBlob(mask) : undefined,
          n,
          size,
          ...(providerOptions.openai ?? {}),
        }),
        // error/success handlers
      });

      return {
        images: response.data.map(item => item.b64_json),
        warnings,
        usage: { inputTokens, outputTokens, totalTokens },
        response: { timestamp, modelId, headers },
        providerMetadata: { 
          openai: { 
            images: response.data.map((item) => ({
              revisedPrompt: item.revised_prompt,
              created: response.created,
              // provider-specific metadata
            }))
          }
        },
      };
    }

    // Standard generation (no files)
    const { value: response, responseHeaders } = await postJsonToApi({
      url: this.config.url({ path: '/images/generations', modelId: this.modelId }),
      headers: combineHeaders(this.config.headers(), headers),
      body: {
        model: this.modelId,
        prompt,
        n,
        size,
        ...(providerOptions.openai ?? {}),
        ...(!hasDefaultResponseFormat(this.modelId)
          ? { response_format: 'b64_json' }
          : {}),
      },
      // error/success handlers
    });

    return { images, warnings, usage, response, providerMetadata };
  }
}
